/**
 * SmartForms - Popup Module
 * Gerencia abertura e fechamento de formulários em popup
 */

import { CSS_CLASSES } from './config.js';
import { log } from './logger.js';

/**
 * Cria estrutura do popup (overlay + container)
 * @param {HTMLElement} formElement - Elemento do formulário a ser exibido
 * @param {string} formId - ID do formulário
 * @returns {Object} { overlay, container, close }
 */
export function createPopup(formElement, formId) {
    // Overlay (backdrop)
    const overlay = document.createElement('div');
    overlay.className = 'hube-smartforms-popup-overlay';
    overlay.setAttribute('data-form-id', formId);

    // Container do popup
    const container = document.createElement('div');
    container.className = 'hube-smartforms-popup-container';

    // Botão de fechar
    const closeButton = document.createElement('button');
    closeButton.className = 'hube-smartforms-popup-close';
    closeButton.innerHTML = '&times;';
    closeButton.setAttribute('type', 'button');
    closeButton.setAttribute('aria-label', 'Fechar');

    // Montar estrutura
    container.appendChild(closeButton);
    container.appendChild(formElement);
    overlay.appendChild(container);

    return { overlay, container, closeButton };
}

/**
 * Abre o popup
 * @param {HTMLElement} overlay - Elemento overlay do popup
 */
export function openPopup(overlay) {
    document.body.appendChild(overlay);

    // Pequeno delay para permitir animação CSS
    requestAnimationFrame(() => {
        overlay.classList.add('hube-smartforms-popup-active');
    });

    // Bloquear scroll do body
    document.body.style.overflow = 'hidden';

    log('[SmartForms] Popup aberto');
}

/**
 * Fecha o popup
 * @param {HTMLElement} overlay - Elemento overlay do popup
 */
export function closePopup(overlay) {
    overlay.classList.remove('hube-smartforms-popup-active');

    // Aguardar animação antes de remover do DOM
    setTimeout(() => {
        if (overlay.parentNode) {
            overlay.parentNode.removeChild(overlay);
        }
    }, 300); // Deve corresponder à duração da animação CSS

    // Restaurar scroll do body
    document.body.style.overflow = '';

    log('[SmartForms] Popup fechado');
}

/**
 * Configura eventos do popup (fechar ao clicar no overlay, ESC, botão fechar)
 * @param {Object} popupElements - { overlay, container, closeButton }
 * @param {Function} onClose - Callback opcional ao fechar
 */
export function setupPopupEvents(popupElements, onClose = null) {
    const { overlay, container, closeButton } = popupElements;

    // Fechar ao clicar no botão X
    closeButton.addEventListener('click', () => {
        closePopup(overlay);
        if (onClose) onClose();
    });

    // Fechar ao clicar no overlay (fora do container)
    overlay.addEventListener('click', (e) => {
        if (e.target === overlay) {
            closePopup(overlay);
            if (onClose) onClose();
        }
    });

    // Fechar ao pressionar ESC
    const escapeHandler = (e) => {
        if (e.key === 'Escape') {
            closePopup(overlay);
            if (onClose) onClose();
            document.removeEventListener('keydown', escapeHandler);
        }
    };

    document.addEventListener('keydown', escapeHandler);
}

/**
 * Cria e configura popup completo para um formulário
 * @param {HTMLElement} formElement - Elemento do formulário
 * @param {string} formId - ID do formulário
 * @param {Object} options - Opções adicionais
 * @returns {Object} { open, close, overlay }
 */
export function createFormPopup(formElement, formId, options = {}) {
    const { overlay, container, closeButton } = createPopup(formElement, formId);

    // Configurar eventos
    setupPopupEvents({ overlay, container, closeButton }, options.onClose);

    return {
        overlay,
        open: () => openPopup(overlay),
        close: () => closePopup(overlay)
    };
}
