/**
 * SmartForms - Page Handler
 * Renderiza formulários em qualquer página
 */

import { renderForm, findFormContainer, renderButton, hideOutOfStockButton, hideAddToCartButton, restoreButtons } from './dom.js';
import { setupFormEventListeners } from './form-handler.js';
import { createFormPopup } from './popup.js';
import { injectCustomCSS } from './styles.js';
import { log, warn } from './logger.js';
import {
    setupVariantListeners,
    detectSelectedVariant,
    onVariantSelected,
    registerFormConfig,
    shouldShowForm
} from './variants.js';

/**
 * Renderiza formulários aplicáveis na página atual
 * Funciona em qualquer tipo de página (produto, conteúdo, home, etc)
 * @param {Object} storeConfig - Configuração completa da loja
 * @param {Object} LS - Objeto global LS da Nuvemshop
 */
export function renderForms(storeConfig, LS) {
    const { forms, globalForms, productForms } = storeConfig;

    // Coletar IDs dos formulários aplicáveis
    const applicableFormIds = [...(globalForms || [])];

    // Se estiver em página de produto, adicionar formulários específicos
    if (LS.product) {
        const productId = LS.product.id.toString();
        log('[SmartForms] Página de produto:', productId);

        const productSpecificForms = productForms[productId] || [];
        applicableFormIds.push(...productSpecificForms);
    } else {
        log('[SmartForms] Página geral (não-produto)');
    }

    log('[SmartForms] Formulários aplicáveis:', applicableFormIds);

    if (applicableFormIds.length === 0) {
        log('[SmartForms] Nenhum formulário configurado para esta página');
        return;
    }

    // Detectar variante inicial (só para páginas de produto)
    let initialVariant = null;
    if (LS.product) {
        initialVariant = detectSelectedVariant(LS);
        log('[SmartForms] Variante inicial:', initialVariant);
    }

    // Renderizar cada formulário
    applicableFormIds.forEach(formId => {
        const formConfig = forms[formId];

        if (!formConfig) {
            warn(`[SmartForms] Configuração não encontrada para form: ${formId}`);
            return;
        }

        // Encontrar container
        const containerInfo = findFormTarget(formConfig);

        if (!containerInfo) {
            warn(`[SmartForms] Container não encontrado para form: ${formId}`);
            return;
        }

        // Verificar se deve renderizar AGORA (baseado em type e estoque)
        const shouldRender = shouldShowForm(formConfig.type, initialVariant);

        let initialElement = null;
        if (shouldRender) {
            initialElement = renderFormNow(formId, formConfig, containerInfo, LS);
        } else {
            log(`[SmartForms] Formulário ${formId} (${formConfig.type}) NÃO renderizado (aguardando mudança de variante)`);
        }

        // Registrar config do formulário para renderização dinâmica
        registerFormConfig(formId, formConfig, containerInfo, LS, renderFormNow, initialElement);
    });

    // Setup de listeners de variantes (só para páginas de produto)
    if (LS.product) {
        setupVariantListeners(LS);

        // Aplicar estado inicial
        if (initialVariant) {
            onVariantSelected(initialVariant, LS);
        }
    }
}

/**
 * Renderiza formulário imediatamente
 * @param {string} formId - ID do formulário
 * @param {Object} formConfig - Configuração do formulário
 * @param {Object} containerInfo - Informações do container
 * @param {Object} LS - Objeto LS da Nuvemshop
 */
export function renderFormNow(formId, formConfig, containerInfo, LS) {
    const displayMode = formConfig.displayMode || 'inline'; // Default: inline

    if (displayMode === 'popup') {
        // Modo POPUP: renderizar botão que abre popup
        return renderFormAsPopup(formId, formConfig, containerInfo, LS);
    } else {
        // Modo INLINE: renderizar formulário direto (comportamento padrão)
        return renderFormInline(formId, formConfig, containerInfo, LS);
    }
}

/**
 * Renderiza formulário inline (comportamento padrão)
 * @param {string} formId - ID do formulário
 * @param {Object} formConfig - Configuração do formulário
 * @param {Object} containerInfo - Informações do container
 * @param {Object} LS - Objeto LS da Nuvemshop
 */
function renderFormInline(formId, formConfig, containerInfo, LS) {
    // Renderizar formulário
    const formElement = renderForm({
        id: formId,
        ...formConfig
    });

    // Injetar no container
    injectFormElement(formElement, containerInfo, formConfig);

    // Setup event listeners
    setupFormEventListeners(formElement, formConfig, LS);

    // Injetar CSS customizado (se houver)
    if (formConfig.customCSS) {
        injectCustomCSS(formId, formConfig.customCSS);
    }

    // Gerenciar visibilidade dos botões de compra
    handleAddToCartButtonVisibility(formConfig, LS);

    log(`[SmartForms] ✅ Formulário inline renderizado: ${formId} (${formConfig.type})`);

    return formElement;
}

/**
 * Renderiza formulário como popup (botão + popup)
 * @param {string} formId - ID do formulário
 * @param {Object} formConfig - Configuração do formulário
 * @param {Object} containerInfo - Informações do container
 * @param {Object} LS - Objeto LS da Nuvemshop
 */
function renderFormAsPopup(formId, formConfig, containerInfo, LS) {
    const buttonLabel = formConfig.buttonLabel || 'Abrir Formulário';

    // Renderizar botão
    const buttonElement = renderButton(buttonLabel, formId);

    // Renderizar formulário (mas não injetar ainda)
    const formElement = renderForm({
        id: formId,
        ...formConfig
    });

    // Setup event listeners no formulário
    setupFormEventListeners(formElement, formConfig, LS);

    // Criar popup
    const popup = createFormPopup(formElement, formId, {
        onClose: () => {
            log(`[SmartForms] Popup fechado: ${formId}`);
        }
    });

    // Configurar botão para abrir popup
    buttonElement.addEventListener('click', () => {
        popup.open();
    });

    // Injetar botão no container
    injectFormElement(buttonElement, containerInfo, formConfig);

    // Injetar CSS customizado (se houver)
    if (formConfig.customCSS) {
        injectCustomCSS(formId, formConfig.customCSS);
    }

    // Gerenciar visibilidade dos botões de compra
    handleAddToCartButtonVisibility(formConfig, LS);

    log(`[SmartForms] ✅ Formulário popup renderizado: ${formId} (${formConfig.type})`);

    return buttonElement;
}

/**
 * Encontra onde o formulário deve ser injetado
 * @param {Object} formConfig - Configuração do formulário
 * @returns {Object|null} { element, type } ou null se não encontrado
 */
function findFormTarget(formConfig) {
    const { selector, shortcode } = formConfig;

    // 1. Tentar via SELECTOR
    if (selector) {
        const element = findFormContainer(selector);
        if (element) {
            return { element, type: 'selector' };
        }
    }

    // 2. Tentar via ATRIBUTO (elemento HTML)
    if (shortcode) {
        const element = document.querySelector(`[hube-form="${shortcode}"]`);
        if (element) {
            return { element, type: 'attribute' };
        }
    }

    // 3. Tentar via TEXTO LITERAL [hube-form="xxx"]
    if (shortcode) {
        const element = findAndReplaceTextLiteral(shortcode);
        if (element) {
            return { element, type: 'literal' };
        }
    }

    return null;
}

/**
 * Busca texto literal [hube-form="xxx"] e cria marcador
 * @param {string} shortcode - Valor do atributo customizado
 * @returns {HTMLElement|null} Elemento marcador criado
 */
function findAndReplaceTextLiteral(shortcode) {
    const searchText = `[hube-form="${shortcode}"]`;
    const bodyHTML = document.body.innerHTML;

    // Verificar se o texto existe
    if (!bodyHTML.includes(searchText)) {
        return null;
    }

    // Criar ID único para o marcador
    const markerId = `hube-form-marker-${shortcode}`;

    // Substituir texto por marcador
    const markerHTML = `<div id="${markerId}"></div>`;
    document.body.innerHTML = bodyHTML.replace(searchText, markerHTML);

    // Retornar elemento marcador
    return document.getElementById(markerId);
}

/**
 * Injeta formulário no container
 * @param {HTMLElement} formElement - Elemento do formulário
 * @param {Object} containerInfo - { element, type }
 * @param {Object} formConfig - Configuração do formulário
 */
function injectFormElement(formElement, containerInfo, formConfig) {
    const { element, type } = containerInfo;
    const position = formConfig.selectorPosition || 'after'; // Default: after

    if (type === 'selector') {
        // Inserir ANTES ou DEPOIS do elemento encontrado pelo seletor
        if (position === 'before') {
            element.insertAdjacentElement('beforebegin', formElement);
            log(`[SmartForms] Formulário inserido ANTES de: ${formConfig.selector}`);
        } else {
            element.insertAdjacentElement('afterend', formElement);
            log(`[SmartForms] Formulário inserido DEPOIS de: ${formConfig.selector}`);
        }
    } else {
        // Atributo ou literal: inserir DENTRO
        element.appendChild(formElement);
        log(`[SmartForms] Formulário inserido DENTRO do container (type: ${type})`);
    }
}

/**
 * Gerencia a visibilidade dos botões de adicionar ao carrinho
 * @param {Object} formConfig - Configuração do formulário
 * @param {Object} LS - Objeto LS da Nuvemshop
 */
function handleAddToCartButtonVisibility(formConfig, LS) {
    // Verifica se produto está fora de estoque
    const isOutOfStock = LS.product && (LS.product.stock === 0 || LS.product.is_visible === false);

    // Se produto fora de estoque → oculta botão .nostock
    if (isOutOfStock) {
        hideOutOfStockButton();
        log(`[SmartForms] 🔒 Botão "Produto Esgotado" ocultado (produto sem estoque)`);
    }

    // Se formulário tem removeAddToCart: true → oculta botão de compra
    if (formConfig.removeAddToCart === true) {
        hideAddToCartButton();
        log(`[SmartForms] 🔒 Botão "Adicionar ao Carrinho" ocultado (removeAddToCart: true)`);
    }
}
