/**
 * SmartForms - Logger
 * Sistema de logs condicionais baseado no ambiente
 */

// Detecta se está em ambiente de desenvolvimento
const isDevelopment = import.meta.env.NODE_ENV === 'development';

/**
 * Log condicional - apenas em desenvolvimento
 * @param  {...any} args - Argumentos para console.log
 */
export function log(...args) {
    if (isDevelopment) {
        console.log(...args);
    }
}

/**
 * Warning condicional - apenas em desenvolvimento
 * @param  {...any} args - Argumentos para console.warn
 */
export function warn(...args) {
    if (isDevelopment) {
        console.warn(...args);
    }
}

/**
 * Error - sempre visível (mesmo em produção)
 * Erros são importantes e devem ser sempre logados
 * @param  {...any} args - Argumentos para console.error
 */
export function error(...args) {
    console.error(...args);
}
