/**
 * SmartForms - API Client
 * Comunicação com API do HUBE com sistema de cache
 */

import { CACHE_CONFIG } from './config.js';
import { makeAuthenticatedRequest } from '../../core/auth/index.js';
import mockData from './mock.json';
import { log, warn, error } from './logger.js';

// Variáveis de ambiente (injetadas pelo Rollup em build time)
const USE_MOCK = import.meta.env.SMARTFORMS_USE_MOCK;
const API_URL = import.meta.env.SMARTFORMS_API_URL;
const CACHE_ENABLED = import.meta.env.CACHE_ENABLED;

/**
 * Busca configurações da loja (formulários disponíveis)
 * Com sistema de cache inteligente
 * @param {number} storeId - ID da loja Nuvemshop
 * @param {string} lang - Código do idioma (es, pt, en)
 * @returns {Promise<Object>} Configurações da loja
 */
export async function fetchStoreConfig(storeId, lang) {
    // Modo desenvolvimento: usar mock (ignora cache)
    if (USE_MOCK) {
        log('[SmartForms] 🔧 Usando mock de dados (cache desabilitado)');
        // Simula delay de rede (300ms)
        await new Promise(resolve => setTimeout(resolve, 300));
        return mockData;
    }

    // Modo produção: usar sistema de cache
    const cacheKey = `${CACHE_CONFIG.key}-${storeId}-${lang}`;
    const cached = getFromCache(cacheKey);

    // 1. USA CACHE SE VÁLIDO (não bloqueia)
    if (cached && !isCacheExpired(cached, CACHE_CONFIG.duration)) {
        log('[SmartForms] ✅ Usando cache válido');

        // 2. ATUALIZA EM BACKGROUND (non-blocking)
        updateCacheInBackground(cacheKey, storeId, lang);

        return cached.data;
    }

    // 3. CACHE EXPIRADO → API Call bloqueante
    log('[SmartForms] 🔄 Cache expirado ou inexistente, buscando da API...');

    try {
        const config = await fetchFromAPI(storeId, lang);

        // Salva no cache
        saveToCache(cacheKey, config);

        return config;

    } catch (err) {
        // 4. FALLBACK para cache antigo (resiliência)
        if (cached) {
            warn('[SmartForms] ⚠️ API falhou, usando cache expirado');
            return cached.data;
        }

        error('[SmartForms] ❌ Sem cache e API falhou');
        throw err;
    }
}

/**
 * Busca dados da API
 * @param {number} storeId - ID da loja
 * @param {string} lang - Idioma
 * @returns {Promise<Object>} Dados da API
 */
async function fetchFromAPI(storeId, lang) {
    const url = `${API_URL}/forms`;

    const response = await makeAuthenticatedRequest(url, {
        method: 'GET',
        headers: {
            'Content-Type': 'application/json'
        }
    }, storeId);

    if (!response.ok) {
        throw new Error(`Erro ao buscar configurações: ${response.status}`);
    }

    return await response.json();
}

/**
 * Atualiza cache em background (non-blocking)
 * @param {string} cacheKey - Chave do cache
 * @param {number} storeId - ID da loja
 * @param {string} lang - Idioma
 */
async function updateCacheInBackground(cacheKey, storeId, lang) {
    try {
        log('[SmartForms] 🔄 Atualizando cache em background...');
        const fresh = await fetchFromAPI(storeId, lang);
        saveToCache(cacheKey, fresh);
        log('[SmartForms] ✅ Cache atualizado em background');
    } catch (err) {
        // Falha silenciosa, continua com cache atual
        warn('[SmartForms] ⚠️ Falha ao atualizar cache em background:', err.message);
    }
}

/**
 * Recupera dados do cache
 * @param {string} key - Chave do cache
 * @returns {Object|null} Dados do cache ou null
 */
function getFromCache(key) {
    try {
        const cached = localStorage.getItem(key);
        if (!cached) return null;

        return JSON.parse(cached);
    } catch (err) {
        warn('[SmartForms] Erro ao ler cache:', err);
        return null;
    }
}

/**
 * Salva dados no cache
 * @param {string} key - Chave do cache
 * @param {Object} data - Dados para cachear
 */
function saveToCache(key, data) {
    try {
        const cacheEntry = {
            data,
            timestamp: Date.now()
        };
        localStorage.setItem(key, JSON.stringify(cacheEntry));
        log('[SmartForms] 💾 Cache salvo');
    } catch (err) {
        warn('[SmartForms] Erro ao salvar cache:', err);
    }
}

/**
 * Verifica se cache expirou
 * @param {Object} cached - Entrada do cache
 * @param {number} duration - Duração do cache em ms
 * @returns {boolean} True se expirado
 */
function isCacheExpired(cached, duration) {
    if (!cached || !cached.timestamp) return true;

    const now = Date.now();
    const age = now - cached.timestamp;

    return age > duration;
}

/**
 * Envia dados do formulário
 * @param {Object} formData - Dados do formulário
 * @returns {Promise<Object>} Resposta da API
 */
export async function sendFormData(formData) {
    // Modo desenvolvimento: simular sucesso
    if (USE_MOCK) {
        log('[SmartForms] 🔧 Mock: Simulando envio de formulário');
        await new Promise(resolve => setTimeout(resolve, 1000));
        return { success: true, message: 'Formulário enviado com sucesso (mock)' };
    }

    // Modo produção: enviar para API real
    try {
        const formId = formData.formId;
        const storeId = formData.storeId;
        const url = `${API_URL}/forms/${formId}/leads`;

        const response = await makeAuthenticatedRequest(url, {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json'
            },
            body: JSON.stringify(formData)
        }, storeId);

        if (!response.ok) {
            throw new Error(`Erro ao enviar formulário: ${response.status}`);
        }

        return await response.json();
    } catch (err) {
        error('[SmartForms] Erro ao enviar formulário:', err);
        throw err;
    }
}
