/**
 * SmartForms - DOM Manipulation
 * Criação dinâmica de formulários baseado em configuração JSON
 */

import { CSS_CLASSES } from './config.js';
import { warn } from './logger.js';

/**
 * Renderiza um formulário completo baseado na configuração
 * @param {Object} formConfig - Configuração do formulário
 * @param {string} formConfig.id - ID único do formulário
 * @param {string} formConfig.shortcode - Atributo customizado
 * @param {Object} formConfig.config - Configurações (title, subtitle, fields, successMessage)
 * @returns {HTMLElement} Elemento do formulário
 */
export function renderForm(formConfig) {
    const { id, shortcode, config } = formConfig;
    const { title, subtitle, fields, successMessage } = config;

    // Container principal
    const container = document.createElement('div');
    container.className = CSS_CLASSES.container;
    container.id = id; // ID do formulário (ex: "form-001")
    container.setAttribute('data-form-id', id);
    container.setAttribute('hube-form', shortcode);

    // Título
    if (title) {
        const titleEl = document.createElement('h3');
        titleEl.className = CSS_CLASSES.title;
        titleEl.textContent = title;
        container.appendChild(titleEl);
    }

    // Subtítulo
    if (subtitle) {
        const subtitleEl = document.createElement('p');
        subtitleEl.className = CSS_CLASSES.subtitle;
        subtitleEl.textContent = subtitle;
        container.appendChild(subtitleEl);
    }

    // Formulário
    const form = document.createElement('form');
    form.className = CSS_CLASSES.form;
    form.noValidate = true;

    // Container de campos
    const fieldsContainer = document.createElement('div');
    fieldsContainer.className = CSS_CLASSES.fields;

    // Renderizar cada campo
    if (fields && Array.isArray(fields)) {
        fields.forEach(fieldConfig => {
            const fieldElement = renderField(fieldConfig);
            if (fieldElement) {
                fieldsContainer.appendChild(fieldElement);
            }
        });
    }

    form.appendChild(fieldsContainer);

    // Botão de submit
    const submitButton = document.createElement('button');
    submitButton.type = 'submit';
    submitButton.className = CSS_CLASSES.submitButton;
    submitButton.textContent = 'Enviar';
    form.appendChild(submitButton);

    container.appendChild(form);

    // Mensagem de sucesso (oculta inicialmente)
    const successEl = document.createElement('div');
    successEl.className = `${CSS_CLASSES.successMessage} ${CSS_CLASSES.hidden}`;
    successEl.textContent = successMessage || 'Formulário enviado com sucesso!';
    container.appendChild(successEl);

    return container;
}

/**
 * Renderiza um campo baseado na configuração
 * @param {Object} fieldConfig - Configuração do campo
 * @returns {HTMLElement} Elemento do campo
 */
export function renderField(fieldConfig) {
    const { type } = fieldConfig;

    const fieldWrapper = document.createElement('div');
    fieldWrapper.className = CSS_CLASSES.field;
    fieldWrapper.setAttribute('data-field-type', type);

    let fieldElement;

    switch (type) {
        case 'text':
        case 'email':
        case 'tel':
        case 'number':
        case 'url':
        case 'date':
            fieldElement = renderInput(fieldConfig);
            break;

        case 'textarea':
            fieldElement = renderTextarea(fieldConfig);
            break;

        case 'select':
            fieldElement = renderSelect(fieldConfig);
            break;

        case 'checkbox':
            fieldElement = renderCheckbox(fieldConfig);
            break;

        case 'radio':
            fieldElement = renderRadio(fieldConfig);
            break;

        default:
            warn(`[SmartForms] Tipo de campo não suportado: ${type}`);
            return null;
    }

    if (fieldElement) {
        // Label (se não for checkbox/radio - eles têm label próprio)
        if (type !== 'checkbox' && type !== 'radio' && fieldConfig.label) {
            const label = document.createElement('label');
            label.className = CSS_CLASSES.label;
            label.textContent = fieldConfig.label;
            if (fieldConfig.required) {
                label.textContent += ' *';
            }
            fieldWrapper.appendChild(label);
        }

        fieldWrapper.appendChild(fieldElement);
    }

    return fieldWrapper;
}

/**
 * Renderiza input (text, email, tel, number, url, date)
 * @param {Object} fieldConfig - Configuração do campo
 * @returns {HTMLInputElement}
 */
export function renderInput(fieldConfig) {
    const input = document.createElement('input');
    input.type = fieldConfig.type;
    input.name = fieldConfig.name;
    input.className = CSS_CLASSES.input;

    if (fieldConfig.placeholder) {
        input.placeholder = fieldConfig.placeholder;
    }

    if (fieldConfig.required) {
        input.required = true;
    }

    if (fieldConfig.min !== undefined) {
        input.min = fieldConfig.min;
    }

    if (fieldConfig.max !== undefined) {
        input.max = fieldConfig.max;
    }

    if (fieldConfig.mask) {
        input.setAttribute('data-mask', fieldConfig.mask);
    }

    return input;
}

/**
 * Renderiza textarea
 * @param {Object} fieldConfig - Configuração do campo
 * @returns {HTMLTextAreaElement}
 */
export function renderTextarea(fieldConfig) {
    const textarea = document.createElement('textarea');
    textarea.name = fieldConfig.name;
    textarea.className = CSS_CLASSES.textarea;

    if (fieldConfig.placeholder) {
        textarea.placeholder = fieldConfig.placeholder;
    }

    if (fieldConfig.required) {
        textarea.required = true;
    }

    if (fieldConfig.rows) {
        textarea.rows = fieldConfig.rows;
    }

    if (fieldConfig.maxlength) {
        textarea.maxLength = fieldConfig.maxlength;
    }

    return textarea;
}

/**
 * Renderiza select
 * @param {Object} fieldConfig - Configuração do campo
 * @returns {HTMLSelectElement}
 */
export function renderSelect(fieldConfig) {
    const select = document.createElement('select');
    select.name = fieldConfig.name;
    select.className = CSS_CLASSES.select;

    if (fieldConfig.required) {
        select.required = true;
    }

    // Adicionar options
    if (fieldConfig.options && Array.isArray(fieldConfig.options)) {
        fieldConfig.options.forEach(optionConfig => {
            const option = document.createElement('option');
            option.value = optionConfig.value;
            option.textContent = optionConfig.label;
            select.appendChild(option);
        });
    }

    return select;
}

/**
 * Renderiza checkbox
 * @param {Object} fieldConfig - Configuração do campo
 * @returns {HTMLElement}
 */
export function renderCheckbox(fieldConfig) {
    const wrapper = document.createElement('label');
    wrapper.className = CSS_CLASSES.label;

    const checkbox = document.createElement('input');
    checkbox.type = 'checkbox';
    checkbox.name = fieldConfig.name;
    checkbox.className = CSS_CLASSES.checkbox;

    if (fieldConfig.required) {
        checkbox.required = true;
    }

    wrapper.appendChild(checkbox);

    const labelText = document.createTextNode(' ' + (fieldConfig.label || ''));
    wrapper.appendChild(labelText);

    if (fieldConfig.required) {
        const required = document.createTextNode(' *');
        wrapper.appendChild(required);
    }

    return wrapper;
}

/**
 * Renderiza radio buttons
 * @param {Object} fieldConfig - Configuração do campo
 * @returns {HTMLElement}
 */
export function renderRadio(fieldConfig) {
    const wrapper = document.createElement('div');
    wrapper.className = CSS_CLASSES.field;

    // Label do grupo
    if (fieldConfig.label) {
        const groupLabel = document.createElement('div');
        groupLabel.className = CSS_CLASSES.label;
        groupLabel.textContent = fieldConfig.label;
        if (fieldConfig.required) {
            groupLabel.textContent += ' *';
        }
        wrapper.appendChild(groupLabel);
    }

    // Criar cada opção de radio
    if (fieldConfig.options && Array.isArray(fieldConfig.options)) {
        fieldConfig.options.forEach(optionConfig => {
            const label = document.createElement('label');
            label.className = CSS_CLASSES.label;

            const radio = document.createElement('input');
            radio.type = 'radio';
            radio.name = fieldConfig.name;
            radio.value = optionConfig.value;
            radio.className = CSS_CLASSES.radio;

            if (fieldConfig.required) {
                radio.required = true;
            }

            label.appendChild(radio);
            label.appendChild(document.createTextNode(' ' + optionConfig.label));

            wrapper.appendChild(label);
        });
    }

    return wrapper;
}

/**
 * Encontra container para injetar formulário baseado no selector
 * @param {string} selector - Seletor CSS do container
 * @returns {HTMLElement|null}
 */
export function findFormContainer(selector) {
    if (!selector) return null;

    const element = document.querySelector(selector);
    if (!element) {
        warn(`[SmartForms] Container não encontrado: ${selector}`);
    }

    return element;
}

/**
 * Mostra mensagem de sucesso e esconde formulário
 * @param {HTMLElement} formContainer - Container do formulário
 */
export function showSuccessMessage(formContainer) {
    const form = formContainer.querySelector(`.${CSS_CLASSES.form}`);
    const successMessage = formContainer.querySelector(`.${CSS_CLASSES.successMessage}`);

    if (form) {
        form.classList.add(CSS_CLASSES.hidden);
    }

    if (successMessage) {
        successMessage.classList.remove(CSS_CLASSES.hidden);
    }
}

/**
 * Mostra mensagem de erro
 * @param {HTMLElement} formContainer - Container do formulário
 * @param {string} message - Mensagem de erro
 */
export function showErrorMessage(formContainer, message) {
    let errorEl = formContainer.querySelector(`.${CSS_CLASSES.errorMessage}`);

    if (!errorEl) {
        errorEl = document.createElement('div');
        errorEl.className = CSS_CLASSES.errorMessage;
        formContainer.appendChild(errorEl);
    }

    errorEl.textContent = message;
    errorEl.classList.remove(CSS_CLASSES.hidden);
}

/**
 * Define estado de loading no botão de submit
 * @param {HTMLElement} formContainer - Container do formulário
 * @param {boolean} loading - Se está carregando
 */
export function setSubmitLoading(formContainer, loading) {
    const submitButton = formContainer.querySelector(`.${CSS_CLASSES.submitButton}`);

    if (submitButton) {
        if (loading) {
            submitButton.disabled = true;
            submitButton.textContent = 'Enviando...';
        } else {
            submitButton.disabled = false;
            submitButton.textContent = 'Enviar';
        }
    }
}

/**
 * Renderiza botão que abre popup
 * @param {string} buttonLabel - Texto do botão
 * @param {string} formId - ID do formulário
 * @returns {HTMLButtonElement} Elemento do botão
 */
export function renderButton(buttonLabel, formId) {
    const button = document.createElement('button');
    button.type = 'button';
    button.className = 'hube-smartforms-popup-trigger';
    button.textContent = buttonLabel || 'Abrir Formulário';
    button.setAttribute('data-form-id', formId);

    return button;
}

/**
 * Oculta o botão "Produto Esgotado" da Nuvemshop
 * Usado quando há formulário e produto está fora de estoque
 */
export function hideOutOfStockButton() {
    const button = document.querySelector('.js-addtocart.nostock');
    if (button && !button.hasAttribute('data-hube-hidden')) {
        button.style.display = 'none';
        button.setAttribute('data-hube-hidden', 'out-of-stock');
    }
}

/**
 * Oculta o botão "Adicionar ao Carrinho" da Nuvemshop
 * Usado quando formulário tem removeAddToCart: true
 */
export function hideAddToCartButton() {
    const button = document.querySelector('.js-addtocart');
    if (button && !button.hasAttribute('data-hube-hidden')) {
        button.style.display = 'none';
        button.setAttribute('data-hube-hidden', 'remove-add-to-cart');
    }
}

/**
 * Restaura botões que foram ocultados pelo SmartForms
 * @param {string} type - Tipo de botão a restaurar ('out-of-stock', 'remove-add-to-cart', 'all')
 */
export function restoreButtons(type = 'all') {
    let selector = '[data-hube-hidden]';

    if (type !== 'all') {
        selector = `[data-hube-hidden="${type}"]`;
    }

    const buttons = document.querySelectorAll(selector);
    buttons.forEach(button => {
        button.style.display = '';
        button.removeAttribute('data-hube-hidden');
    });
}
