/**
 * SmartForms Feature
 * Sistema de formulários dinâmicos para Nuvemshop
 *
 * Permite criar e gerenciar múltiplos formulários customizados
 * que podem ser aplicados globalmente ou em produtos específicos.
 */

import { loadStylesheet } from './styles.js';
import { fetchStoreConfig } from './api.js';
import { renderForms } from './product-page.js';
import { log, error } from './logger.js';

// Variável de ambiente injetada em build time
const USE_MOCK = import.meta.env.SMARTFORMS_USE_MOCK;

/**
 * Verifica se LS (Nuvemshop API) está disponível
 * @returns {boolean}
 */
function checkNuvemshopAPI() {
    if (typeof window.LS === 'undefined') {
        error('[SmartForms] API LS da Nuvemshop não encontrada');
        return false;
    }
    return true;
}

/**
 * Inicializa a feature SmartForms
 */
async function init() {
    log('[SmartForms] 🚀 Inicializando feature...');

    // Modo MOCK: pula validação da API Nuvemshop
    if (USE_MOCK) {
        log('[SmartForms] 🔧 Modo MOCK ativado - pulando validação de autenticação');
    } else {
        // Modo PRODUÇÃO: valida API Nuvemshop
        if (!checkNuvemshopAPI()) {
            return;
        }
    }

    const LS = window.LS;

    // Carregar estilos
    loadStylesheet();

    try {
        // Buscar configurações da loja (formulários disponíveis)
        const storeConfig = await fetchStoreConfig(LS.store.id, LS.langCode);

        log('[SmartForms] ⚙️  Configuração carregada:', storeConfig);

        // Renderizar formulários (funciona em qualquer tipo de página)
        renderForms(storeConfig, LS);

        log('[SmartForms] ✅ Feature inicializada com sucesso');

    } catch (err) {
        error('[SmartForms] ❌ Erro ao inicializar feature:', err);
    }
}

// Expõe no namespace global para ser carregado dinamicamente
window.HubeFeatures = window.HubeFeatures || {};
window.HubeFeatures.smartforms = {
    init
};
