/**
 * SmartForms - Form Handler
 * Gerencia eventos e envio dos formulários
 */

import { CSS_CLASSES } from './config.js';
import { sendFormData } from './api.js';
import { showSuccessMessage, showErrorMessage, setSubmitLoading } from './dom.js';
import { log, warn, error } from './logger.js';

/**
 * Configura event listeners para um formulário
 * @param {HTMLElement} formElement - Elemento do formulário
 * @param {Object} formConfig - Configuração do formulário
 * @param {Object} LS - Objeto global LS da Nuvemshop
 */
export function setupFormEventListeners(formElement, formConfig, LS) {
    const form = formElement.querySelector(`.${CSS_CLASSES.form}`);

    if (!form) {
        warn('[SmartForms] Formulário não encontrado no container');
        return;
    }

    form.addEventListener('submit', (event) => {
        handleFormSubmit(event, formElement, formConfig, LS);
    });
}

/**
 * Handler para submit do formulário
 * @param {Event} event - Evento de submit
 * @param {HTMLElement} formElement - Container do formulário
 * @param {Object} formConfig - Configuração do formulário
 * @param {Object} LS - Objeto global LS da Nuvemshop
 */
async function handleFormSubmit(event, formElement, formConfig, LS) {
    event.preventDefault();

    const form = event.target;

    // Validação HTML5 nativa
    if (!form.checkValidity()) {
        form.reportValidity();
        return;
    }

    // Coletar dados do formulário
    const formData = new FormData(form);
    const data = {};

    formData.forEach((value, key) => {
        data[key] = value;
    });

    log('[SmartForms] Dados do formulário:', data);

    // Adicionar metadados
    const payload = {
        formId: formElement.getAttribute('data-form-id'),
        storeId: LS.store.id,
        lang: LS.langCode,
        product_id: LS.product?.id,
        data: data
    };

    // Log do payload completo (apenas em desenvolvimento)
    log('[SmartForms] 📦 Payload completo:', payload);
    log('[SmartForms] 📦 Payload JSON:', JSON.stringify(payload, null, 2));

    // Loading
    setSubmitLoading(formElement, true);

    try {
        // Enviar para API
        await sendFormData(payload);

        log('[SmartForms] ✅ Formulário enviado com sucesso');

        // Salvar no localStorage (opcional)
        saveFormDataToLocalStorage(data);

        // Mostrar mensagem de sucesso
        showSuccessMessage(formElement);

    } catch (err) {
        error('[SmartForms] ❌ Erro ao enviar formulário:', err);

        // Mostrar mensagem de erro
        showErrorMessage(formElement, 'Erro ao enviar formulário. Tente novamente.');

    } finally {
        // Remover loading
        setSubmitLoading(formElement, false);
    }
}

/**
 * Salva dados do formulário no localStorage
 * @param {Object} data - Dados do formulário
 */
function saveFormDataToLocalStorage(data) {
    try {
        // Salvar email se existir (para preenchimento automático)
        if (data.email) {
            localStorage.setItem('hube-form-email', data.email);
        }

        // Salvar telefone se existir
        if (data.phone) {
            localStorage.setItem('hube-form-phone', data.phone);
        }
    } catch (err) {
        warn('[SmartForms] Erro ao salvar no localStorage:', err);
    }
}

/**
 * Recupera dados salvos do localStorage
 * @returns {Object} Dados salvos
 */
export function getSavedFormData() {
    try {
        return {
            email: localStorage.getItem('hube-form-email') || '',
            phone: localStorage.getItem('hube-form-phone') || ''
        };
    } catch (err) {
        warn('[SmartForms] Erro ao recuperar do localStorage:', err);
        return {};
    }
}
