/**
 * Out of Stock - Styles
 * CSS do widget de notificação
 */

import { log } from './logger.js';

export const WIDGET_CSS = `
#stock-notification-container {
    display: none;
    border: 1px solid #6c757d;
    border-radius: 7px;
    clear: both;
    margin-top: 1rem;
}

#stock-notification-container #stock-notification-modal-dialog {
    background-color: #fefefe;
    margin: 15% auto;
    padding: 30px 30px 20px 30px;
    border: 1px solid #888;
    border-radius: 4px;
    width: 40%;
    max-width: 500px;
    min-width: 312px;
    font-size: 16px;
}

@media only screen and (max-width: 480px) {
    #stock-notification-container #stock-notification-modal-dialog {
        margin: 35% auto;
        padding: 30px 20px 10px 20px;
        width: 95%;
    }
}

#stock-notification-container #stock-notification-modal-dialog div,
#stock-notification-container #stock-notification-modal-dialog input {
    margin-bottom: 20px;
    margin-top: 0;
}

#stock-notification-container #stock-notification-modal-dialog::backdrop {
    background-color: rgba(0, 0, 0, 0.4);
}

#stock-notification-container #stock-notification-close-button {
    color: #aaa;
    font-size: 28px;
    position: absolute;
    top: 10px;
    right: 15px;
}

#stock-notification-container #stock-notification-close-button:hover,
#stock-notification-container #stock-notification-close-button:focus {
    color: black;
    text-decoration: none;
    cursor: pointer;
}

#stock-notification-container #stock-notification-product-name {
    text-transform: uppercase;
    font-size: larger;
    font-weight: bold;
}

#stock-notification-container #stock-notification-request-message {
    padding: 8px 20px;
    cursor: pointer;
    text-align: center;
}

#stock-notification-container #stock-notification-success-message {
    display: none;
    text-align: center;
}

#stock-notification-container #stock-notification-form {
    display: flex;
    flex-direction: column;
    width: 100%;
}

#stock-notification-container #stock-notification-form span {
    display: block;
    overflow: hidden;
    flex-grow: 1;
}

#stock-notification-container #stock-notification-form div,
#stock-notification-container #stock-notification-form input {
    height: initial;
}

#stock-notification-container #stock-notification-form #stock-notification-email,
#stock-notification-container #stock-notification-form #stock-notification-phone,
#stock-notification-container #stock-notification-form #stock-notification-quantity {
    width: 100%;
    padding: 8px 20px;
    border: 1px solid #ced4da;
    box-sizing: border-box;
    font-size: 16px;
}

#stock-notification-container #stock-notification-form #stock-notification-email::placeholder,
#stock-notification-container #stock-notification-form #stock-notification-phone::placeholder,
#stock-notification-container #stock-notification-form #stock-notification-quantity::placeholder {
    color: #757575;
}

#stock-notification-container #stock-notification-form #stock-notification-submit {
    white-space: nowrap;
    padding: 8px 15px;
    border: 1px solid #6c757d;
    background-color: #efefef;
    margin-bottom: 0;
    color: #000;
    cursor: pointer;
}

#stock-notification-container div.stock-notification-powered-by {
    text-align: right;
    padding-top: 10px;
    font-size: 0.6em;
    margin-bottom: 0;
}

.notification-list-button {
    margin-top: 1rem;
    border: 1px solid #6c757d;
    color: #6c757d;
    padding: 3px;
    text-align: center;
}

/* Theme-specific adjustments */
#stock-notification-container.zen,
#stock-notification-container.recife,
#stock-notification-container.toluca,
#stock-notification-container.morelia,
#stock-notification-container.uyuni,
#stock-notification-container.new_linkedman,
#stock-notification-container.baires,
#stock-notification-container.cubo,
#stock-notification-container.luxury {
    border-radius: 0;
}

#stock-notification-container.idea {
    border-radius: 50px;
    margin-bottom: 1rem;
    padding: 5px 10px;
}

#stock-notification-container.lima {
    border-radius: 40px;
}

.notification-list-button.idea {
    margin-top: 0;
    border-radius: 6px;
}

.notification-list-button.lima {
    border-radius: 50px;
    padding: 10px 15px;
}

/* ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
   POPUP STYLES
   CSS genérico e adaptável para popups de formulários
   ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━ */

/* Overlay/Backdrop */
.hube-smartforms-popup-overlay {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: rgba(0, 0, 0, 0.5);
    z-index: 9999;
    display: flex;
    align-items: center;
    justify-content: center;
    opacity: 0;
    transition: opacity 0.3s ease;
    padding: 20px;
    box-sizing: border-box;
}

.hube-smartforms-popup-overlay.hube-smartforms-popup-active {
    opacity: 1;
}

/* Container do Popup */
.hube-smartforms-popup-container {
    --popup-bg: #fff;
    --popup-max-width: 500px;
    --popup-padding: 30px;
    --popup-border-radius: 8px;
    --popup-box-shadow: 0 4px 20px rgba(0, 0, 0, 0.15);

    position: relative;
    background: var(--popup-bg);
    max-width: var(--popup-max-width);
    width: 100%;
    padding: var(--popup-padding);
    border-radius: var(--popup-border-radius);
    box-shadow: var(--popup-box-shadow);
    max-height: 90vh;
    overflow-y: auto;
    transform: scale(0.9);
    transition: transform 0.3s ease;
}

.hube-smartforms-popup-active .hube-smartforms-popup-container {
    transform: scale(1);
}

/* Botão de Fechar */
.hube-smartforms-popup-close {
    --close-size: 32px;
    --close-color: #999;
    --close-hover-color: #333;

    position: absolute;
    top: 10px;
    right: 10px;
    width: var(--close-size);
    height: var(--close-size);
    border: none;
    background: transparent;
    font-size: 32px;
    line-height: 1;
    color: var(--close-color);
    cursor: pointer;
    padding: 0;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: color 0.2s ease;
}

.hube-smartforms-popup-close:hover {
    color: var(--close-hover-color);
}

/* Botão que abre o popup */
.hube-smartforms-popup-trigger {
    --trigger-bg: #007bff;
    --trigger-color: #fff;
    --trigger-padding: 12px 24px;
    --trigger-border-radius: 4px;
    --trigger-hover-bg: #0056b3;

    display: inline-block;
    background: var(--trigger-bg);
    color: var(--trigger-color);
    padding: var(--trigger-padding);
    border: none;
    border-radius: var(--trigger-border-radius);
    cursor: pointer;
    font-size: 16px;
    text-align: center;
    transition: background 0.2s ease;
}

.hube-smartforms-popup-trigger:hover {
    background: var(--trigger-hover-bg);
}

/* Responsivo */
@media (max-width: 768px) {
    .hube-smartforms-popup-container {
        --popup-max-width: 100%;
        --popup-padding: 20px;
        max-height: 85vh;
    }

    .hube-smartforms-popup-overlay {
        padding: 10px;
    }
}

@media (max-width: 480px) {
    .hube-smartforms-popup-container {
        --popup-padding: 15px;
    }

    .hube-smartforms-popup-close {
        --close-size: 28px;
    }
}

/* ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
   FORM STYLES
   CSS genérico e adaptável para campos de formulário
   ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━ */

/* Container do Formulário */
.hube-form-container {
    --form-spacing: 20px;
    --form-max-width: 100%;

    width: 100%;
    max-width: var(--form-max-width);
    margin: 0 auto;
}

/* Título e Subtítulo */
.hube-form-title {
    --title-color: #333;
    --title-size: 24px;
    --title-weight: 600;
    --title-margin: 0 0 10px 0;

    color: var(--title-color);
    font-size: var(--title-size);
    font-weight: var(--title-weight);
    margin: var(--title-margin);
    line-height: 1.3;
}

.hube-form-subtitle {
    --subtitle-color: #666;
    --subtitle-size: 14px;
    --subtitle-margin: 0 0 20px 0;

    color: var(--subtitle-color);
    font-size: var(--subtitle-size);
    margin: var(--subtitle-margin);
    line-height: 1.5;
}

/* Form */
.hube-form {
    display: flex;
    flex-direction: column;
    gap: var(--form-spacing);
}

/* Container de Campos */
.hube-form-fields {
    display: flex;
    flex-direction: column;
    gap: var(--form-spacing);
}

/* Campo Individual */
.hube-form-field {
    display: flex;
    flex-direction: column;
    gap: 6px;
}

/* Labels */
.hube-form-label {
    --label-color: #333;
    --label-size: 14px;
    --label-weight: 500;

    color: var(--label-color);
    font-size: var(--label-size);
    font-weight: var(--label-weight);
    display: block;
}

/* Inputs (text, email, tel, number, url, date) */
.hube-form-input {
    --input-bg: #fff;
    --input-border: 1px solid #ddd;
    --input-border-radius: 4px;
    --input-padding: 10px 12px;
    --input-font-size: 14px;
    --input-color: #333;
    --input-focus-border: #007bff;
    --input-focus-shadow: 0 0 0 3px rgba(0, 123, 255, 0.1);

    width: 100%;
    padding: var(--input-padding);
    font-size: var(--input-font-size);
    color: var(--input-color);
    background: var(--input-bg);
    border: var(--input-border);
    border-radius: var(--input-border-radius);
    box-sizing: border-box;
    transition: border-color 0.2s ease, box-shadow 0.2s ease;
}

.hube-form-input:focus {
    outline: none;
    border-color: var(--input-focus-border);
    box-shadow: var(--input-focus-shadow);
}

.hube-form-input::placeholder {
    color: #999;
}

/* Textarea */
.hube-form-textarea {
    --textarea-bg: #fff;
    --textarea-border: 1px solid #ddd;
    --textarea-border-radius: 4px;
    --textarea-padding: 10px 12px;
    --textarea-font-size: 14px;
    --textarea-color: #333;
    --textarea-focus-border: #007bff;
    --textarea-focus-shadow: 0 0 0 3px rgba(0, 123, 255, 0.1);
    --textarea-min-height: 100px;

    width: 100%;
    min-height: var(--textarea-min-height);
    padding: var(--textarea-padding);
    font-size: var(--textarea-font-size);
    color: var(--textarea-color);
    background: var(--textarea-bg);
    border: var(--textarea-border);
    border-radius: var(--textarea-border-radius);
    box-sizing: border-box;
    font-family: inherit;
    resize: vertical;
    transition: border-color 0.2s ease, box-shadow 0.2s ease;
}

.hube-form-textarea:focus {
    outline: none;
    border-color: var(--textarea-focus-border);
    box-shadow: var(--textarea-focus-shadow);
}

.hube-form-textarea::placeholder {
    color: #999;
}

/* Select */
.hube-form-select {
    --select-bg: #fff;
    --select-border: 1px solid #ddd;
    --select-border-radius: 4px;
    --select-padding: 10px 12px;
    --select-font-size: 14px;
    --select-color: #333;
    --select-focus-border: #007bff;
    --select-focus-shadow: 0 0 0 3px rgba(0, 123, 255, 0.1);

    width: 100%;
    padding: var(--select-padding);
    font-size: var(--select-font-size);
    color: var(--select-color);
    background: var(--select-bg);
    border: var(--select-border);
    border-radius: var(--select-border-radius);
    box-sizing: border-box;
    cursor: pointer;
    transition: border-color 0.2s ease, box-shadow 0.2s ease;
}

.hube-form-select:focus {
    outline: none;
    border-color: var(--select-focus-border);
    box-shadow: var(--select-focus-shadow);
}

/* Checkbox */
.hube-form-checkbox {
    --checkbox-size: 18px;
    --checkbox-color: #007bff;

    width: var(--checkbox-size);
    height: var(--checkbox-size);
    cursor: pointer;
    accent-color: var(--checkbox-color);
}

/* Radio */
.hube-form-radio {
    --radio-size: 18px;
    --radio-color: #007bff;

    width: var(--radio-size);
    height: var(--radio-size);
    cursor: pointer;
    accent-color: var(--radio-color);
}

/* Botão Submit */
.hube-form-submit {
    --submit-bg: #007bff;
    --submit-color: #fff;
    --submit-padding: 12px 24px;
    --submit-border-radius: 4px;
    --submit-font-size: 16px;
    --submit-hover-bg: #0056b3;

    padding: var(--submit-padding);
    font-size: var(--submit-font-size);
    color: var(--submit-color);
    background: var(--submit-bg);
    border: none;
    border-radius: var(--submit-border-radius);
    cursor: pointer;
    font-weight: 500;
    transition: background 0.2s ease;
}

.hube-form-submit:hover:not(:disabled) {
    background: var(--submit-hover-bg);
}

.hube-form-submit:disabled {
    opacity: 0.6;
    cursor: not-allowed;
}

/* Mensagem de Sucesso */
.hube-form-success {
    --success-bg: #d4edda;
    --success-color: #155724;
    --success-border: 1px solid #c3e6cb;
    --success-padding: 12px 16px;
    --success-border-radius: 4px;

    padding: var(--success-padding);
    background: var(--success-bg);
    color: var(--success-color);
    border: var(--success-border);
    border-radius: var(--success-border-radius);
}

/* Mensagem de Erro */
.hube-form-error {
    --error-bg: #f8d7da;
    --error-color: #721c24;
    --error-border: 1px solid #f5c6cb;
    --error-padding: 12px 16px;
    --error-border-radius: 4px;

    padding: var(--error-padding);
    background: var(--error-bg);
    color: var(--error-color);
    border: var(--error-border);
    border-radius: var(--error-border-radius);
}

/* Hidden */
.hube-form-hidden {
    display: none !important;
}

/* Responsivo */
@media (max-width: 768px) {
    .hube-form-container {
        --form-spacing: 16px;
    }

    .hube-form-title {
        --title-size: 20px;
    }

    .hube-form-input,
    .hube-form-textarea,
    .hube-form-select,
    .hube-form-submit {
        font-size: 16px; /* Previne zoom no iOS */
    }
}
`;

/**
 * Injeta o CSS do widget no <head>
 */
export function loadStylesheet() {
    const styleElement = document.createElement('style');
    styleElement.type = 'text/css';
    styleElement.textContent = WIDGET_CSS;
    document.head.appendChild(styleElement);
}

/**
 * Injeta CSS customizado de um formulário específico no <head>
 * @param {string} formId - ID do formulário
 * @param {string} customCSS - CSS customizado a ser injetado
 */
export function injectCustomCSS(formId, customCSS) {
    // Se não houver CSS customizado, não faz nada
    if (!customCSS || customCSS.trim() === '') {
        return;
    }

    // ID único para o elemento style
    const styleId = `hube-smartforms-custom-css-${formId}`;

    // Verificar se já existe (evitar duplicação)
    let styleElement = document.getElementById(styleId);

    if (!styleElement) {
        // Criar novo elemento style
        styleElement = document.createElement('style');
        styleElement.type = 'text/css';
        styleElement.id = styleId;
        document.head.appendChild(styleElement);
    }

    // Injetar CSS
    styleElement.textContent = customCSS;

    log(`[SmartForms] CSS customizado injetado para form: ${formId}`);
}

/**
 * Remove CSS customizado de um formulário específico
 * @param {string} formId - ID do formulário
 */
export function removeCustomCSS(formId) {
    const styleId = `hube-smartforms-custom-css-${formId}`;
    const styleElement = document.getElementById(styleId);

    if (styleElement) {
        styleElement.parentNode.removeChild(styleElement);
        log(`[SmartForms] CSS customizado removido para form: ${formId}`);
    }
}
