/**
 * SmartForms - Variants Handler
 * Gerenciamento de variantes e renderização dinâmica de formulários
 */

import { log, warn } from './logger.js';
import { hideOutOfStockButton, restoreButtons } from './dom.js';

let selectedVariant = null;
let formConfigs = new Map(); // Map<formId, { config, containerInfo, LS, element, renderFn }>

/**
 * Retorna variante atualmente selecionada
 * @returns {Object|null} Variante selecionada
 */
export function getSelectedVariant() {
    return selectedVariant;
}

/**
 * Define a variante selecionada
 * @param {Object} variant - Variante do produto
 */
export function setSelectedVariant(variant) {
    selectedVariant = variant;
}

/**
 * Registra configuração de um formulário para renderização dinâmica
 * @param {string} formId - ID do formulário
 * @param {Object} formConfig - Configuração do formulário
 * @param {Object} containerInfo - Info do container { element, type }
 * @param {Object} LS - Objeto LS da Nuvemshop
 * @param {Function} renderFn - Função de renderização
 * @param {HTMLElement|null} initialElement - Elemento já renderizado (opcional)
 */
export function registerFormConfig(formId, formConfig, containerInfo, LS, renderFn, initialElement = null) {
    formConfigs.set(formId, {
        config: formConfig,
        containerInfo,
        LS,
        renderFn,
        element: initialElement
    });
    log(`[SmartForms] Config registrada: ${formId} (${formConfig.type}) - ${initialElement ? 'Renderizado' : 'Pendente'}`);
}

/**
 * Detecta a variante selecionada pelos selects/inputs do formulário
 * @param {Object} LS - Objeto global LS da Nuvemshop
 * @returns {Object|null} Variante detectada
 */
export function detectSelectedVariant(LS) {
    if (!LS || !LS.variants) return null;

    const currentVariant = {};
    let selects = document.querySelectorAll('[data-store^="product-form"] select[name^=variation]');

    if (selects.length === 0) {
        selects = document.querySelectorAll('[data-store^="product-form"] input[name^=variation]');
    }

    // Filtrar apenas inputs radio checked
    if (selects.length > 0 && selects[0].type === 'radio') {
        selects = Array.from(selects).filter(input => input.checked);
    }

    selects.forEach(select => {
        const match = /variation\[(\d+)\]/.exec(select.getAttribute('name'));
        if (match) {
            const key = 'option' + match[1];
            currentVariant[key] = select.value;
        }
    });

    // Encontrar variante que corresponde às opções selecionadas
    let matchedVariant = null;

    for (const variant of LS.variants) {
        let matches = true;

        for (const key in currentVariant) {
            if (variant[key] !== currentVariant[key]) {
                matches = false;
                break;
            }
        }

        if (matches) {
            matchedVariant = variant;
            break;
        }
    }

    return matchedVariant;
}

/**
 * Callback quando variante é selecionada
 * Renderiza ou remove formulários do DOM baseado no critério
 * @param {Object} variant - Variante selecionada
 * @param {Object} LS - Objeto global LS da Nuvemshop
 */
export function onVariantSelected(variant, LS) {
    // Se não há variante, pega a primeira disponível ou a primeira da lista
    if (!variant && LS && LS.variants) {
        variant = LS.variants.find(v => v.available) || LS.variants[0];
    }

    if (!variant) return;

    setSelectedVariant(variant);

    // Verificar se produto está sem estoque
    const isOutOfStock = variant.stock === 0 || variant.is_visible === false;

    log(`[SmartForms] Variante selecionada:`, {
        id: variant.id,
        stock: variant.stock,
        isOutOfStock
    });

    // Processar cada formulário registrado
    formConfigs.forEach((formData, formId) => {
        const { config, containerInfo, LS: formLS, element, renderFn } = formData;
        const shouldShow = shouldShowForm(config.type, variant);

        if (shouldShow && !element) {
            // RENDERIZAR: Precisa mostrar mas não está renderizado
            log(`[SmartForms] 🔄 Renderizando formulário: ${formId}`);
            const renderedElement = renderFn(formId, config, containerInfo, formLS);
            formConfigs.get(formId).element = renderedElement;

        } else if (!shouldShow && element) {
            // REMOVER: Não precisa mostrar e está renderizado
            log(`[SmartForms] 🗑️ Removendo formulário: ${formId}`);
            element.remove();
            formConfigs.get(formId).element = null;

        } else if (shouldShow && element) {
            log(`[SmartForms] ✅ Formulário ${formId} já renderizado`);
        } else {
            log(`[SmartForms] ⏸️ Formulário ${formId} aguardando critério`);
        }
    });

    // Gerenciar visibilidade dos botões de compra baseado no estado atual
    handleButtonsOnVariantChange(variant);
}

/**
 * Registra listeners para mudança de variante
 * @param {Object} LS - Objeto global LS da Nuvemshop
 */
export function setupVariantListeners(LS) {
    if (!LS || typeof LS.registerOnChangeVariant !== 'function') {
        warn('[SmartForms] LS.registerOnChangeVariant não disponível');
        return;
    }

    LS.registerOnChangeVariant((variant) => {
        onVariantSelected(variant, LS);
    });

    // Caso específico para tema Cancun
    if (LS.theme && LS.theme.code === 'cancun') {
        const variantInputs = document.querySelectorAll('input.js-theme-change-variant');
        variantInputs.forEach(input => {
            input.addEventListener('change', () => {
                const variant = detectSelectedVariant(LS);
                onVariantSelected(variant, LS);
            });
        });
    }

    log('[SmartForms] Listeners de variantes configurados');
}

/**
 * Verifica se deve mostrar formulário baseado no tipo e estoque
 * @param {string} formType - Tipo do formulário
 * @param {Object} variant - Variante do produto
 * @returns {boolean} Se deve mostrar
 */
export function shouldShowForm(formType, variant) {
    if (formType === 'general') {
        return true; // Sempre mostra
    }

    if (formType === 'out-of-stock') {
        if (!variant) return false;
        return variant.stock === 0 || variant.is_visible === false;
    }

    return true; // Default: mostra
}

/**
 * Gerencia visibilidade dos botões de compra quando variante muda
 * @param {Object} variant - Variante selecionada
 */
function handleButtonsOnVariantChange(variant) {
    if (!variant) return;

    const isOutOfStock = variant.stock === 0 || variant.is_visible === false;

    // Verifica se há formulários ativos (renderizados)
    const hasActiveForm = Array.from(formConfigs.values()).some(formData => formData.element !== null);

    if (isOutOfStock && hasActiveForm) {
        // Produto fora de estoque + tem formulário ativo → oculta botão .nostock
        hideOutOfStockButton();
        log(`[SmartForms] 🔒 Botão "Produto Esgotado" ocultado (variante sem estoque)`);
    } else if (!isOutOfStock) {
        // Produto voltou ao estoque → restaura botão de out-of-stock
        restoreButtons('out-of-stock');
        log(`[SmartForms] 🔓 Botão "Produto Esgotado" restaurado (variante com estoque)`);
    }
}
